from typing import Any, Callable, List, Optional, Sequence

from fastapi._compat import ModelField
from fastapi.security.base import SecurityBase


class SecurityRequirement:
    def __init__(
        self, security_scheme: SecurityBase, scopes: Optional[Sequence[str]] = None
    ):
        """Initialize a security requirement.

        Args:
            security_scheme: The security scheme instance (subclass of SecurityBase).
            scopes: Optional sequence of scopes required for this security scheme.
        """
        self.security_scheme = security_scheme
        self.scopes = scopes


class Dependant:
    def __init__(
        self,
        *,
        path_params: Optional[List[ModelField]] = None,
        query_params: Optional[List[ModelField]] = None,
        header_params: Optional[List[ModelField]] = None,
        cookie_params: Optional[List[ModelField]] = None,
        body_params: Optional[List[ModelField]] = None,
        dependencies: Optional[List["Dependant"]] = None,
        security_schemes: Optional[List[SecurityRequirement]] = None,
        name: Optional[str] = None,
        call: Optional[Callable[..., Any]] = None,
        request_param_name: Optional[str] = None,
        websocket_param_name: Optional[str] = None,
        http_connection_param_name: Optional[str] = None,
        response_param_name: Optional[str] = None,
        background_tasks_param_name: Optional[str] = None,
        security_scopes_param_name: Optional[str] = None,
        security_scopes: Optional[List[str]] = None,
        use_cache: bool = True,
        path: Optional[str] = None,
    ) -> None:
        """Create a Dependant instance describing dependencies and parameters for a route.

        This object is used internally to describe function parameters, dependencies,
        and security requirements for path operation callables.

        Args:
            path_params: ModelField list for path parameters.
            query_params: ModelField list for query parameters.
            header_params: ModelField list for header parameters.
            cookie_params: ModelField list for cookie parameters.
            body_params: ModelField list for body parameters.
            dependencies: List of other Dependant instances this one depends on.
            security_schemes: List of SecurityRequirement instances.
            name: Optional name for the dependant.
            call: The callable this dependant represents.
            request_param_name: Name of the request parameter, if any.
            websocket_param_name: Name of the websocket parameter, if any.
            http_connection_param_name: Name of the HTTP connection parameter, if any.
            response_param_name: Name of the response parameter, if any.
            background_tasks_param_name: Name of the background tasks parameter, if any.
            security_scopes_param_name: Name of the parameter used to pass security scopes.
            security_scopes: List of security scopes.
            use_cache: Whether to cache the dependency resolution.
            path: Optional path associated with this dependant.
        """
        self.path_params = path_params or []
        self.query_params = query_params or []
        self.header_params = header_params or []
        self.cookie_params = cookie_params or []
        self.body_params = body_params or []
        self.dependencies = dependencies or []
        self.security_requirements = security_schemes or []
        self.request_param_name = request_param_name
        self.websocket_param_name = websocket_param_name
        self.http_connection_param_name = http_connection_param_name
        self.response_param_name = response_param_name
        self.background_tasks_param_name = background_tasks_param_name
        self.security_scopes = security_scopes
        self.security_scopes_param_name = security_scopes_param_name
        self.name = name
        self.call = call
        self.use_cache = use_cache
        # Store the path to be able to re-generate a dependable from it in overrides
        self.path = path
        # Save the cache key at creation to optimize performance
        self.cache_key = (self.call, tuple(sorted(set(self.security_scopes or []))))